'use client';

import { gsap, useGSAP } from '../../../lib/gsap';

export const HomeTransitions = () => {
  useGSAP(() => {
    const media = gsap.matchMedia();

    media.add('(prefers-reduced-motion: no-preference)', () => {
      const productsSection = document.querySelector<HTMLElement>('[data-home-products]');

      if (!productsSection) {
        return;
      }

      gsap.set(productsSection, { willChange: 'transform, opacity' });

      const tween = gsap.fromTo(
        productsSection,
        {
          y: 56,
          autoAlpha: 0.94,
        },
        {
          y: 0,
          autoAlpha: 1,
          ease: 'none',
          scrollTrigger: {
            trigger: productsSection,
            start: 'top 92%',
            end: 'top 68%',
            scrub: 0.8,
            fastScrollEnd: true,
            invalidateOnRefresh: true,
          },
        }
      );

      return () => {
        tween.scrollTrigger?.kill();
        tween.kill();
        gsap.set(productsSection, { clearProps: 'willChange' });
      };
    });

    return () => media.revert();
  });

  return null;
};

'use client';

import { gsap, useGSAP } from '../../../lib/gsap';

export const HomeTransitions = () => {
  useGSAP(() => {
    const media = gsap.matchMedia();

    media.add('(prefers-reduced-motion: no-preference)', () => {
      const productsSection = document.querySelector<HTMLElement>('[data-home-products]');

      if (!productsSection) {
        return;
      }

      gsap.set(productsSection, { willChange: 'transform, opacity' });

      const tween = gsap.fromTo(
        productsSection,
        {
          y: 56,
          autoAlpha: 0.94,
        },
        {
          y: 0,
          autoAlpha: 1,
          ease: 'none',
          scrollTrigger: {
            trigger: productsSection,
            start: 'top 92%',
            end: 'top 68%',
            scrub: 0.8,
            fastScrollEnd: true,
            invalidateOnRefresh: true,
          },
          onComplete: () => {
            // Clear will-change after animation completes for better performance
            gsap.set(productsSection, { clearProps: 'willChange' });
          },
        }
      );

      return () => {
        tween.scrollTrigger?.kill();
        tween.kill();
        // Ensure cleanup of all animation properties set by GSAP
        gsap.set(productsSection, { clearProps: 'all' });
      };
    });

    return () => media.revert();
  });

  return null;
};

@import '@workspace/ui/globals.css';

/* ─── Sticker loader bounce ─────────────────────────────────────── */
/*
  Physics-accurate ball-bounce keyframe:
    0 → 50 %  : launched upward — decelerates to peak  (ease-out)
    50 → 100% : falls from peak — accelerates to floor (ease-in)
*/
@keyframes sticker-logo-bounce {
    0% {
        transform: translateY(0) scaleX(1.1) scaleY(0.9);
        animation-timing-function: cubic-bezier(0.215, 0.61, 0.355, 1); /* ease-out cubic */
    }
    50% {
        transform: translateY(-78px) scaleX(0.95) scaleY(1.05) rotate(18deg);
        animation-timing-function: cubic-bezier(0.55, 0.055, 0.675, 0.19); /* ease-in cubic */
    }
    100% {
        transform: translateY(0) scaleX(1.1) scaleY(0.9);
    }
}

/* let the logo travel outside the SVG canvas */
.sticker-loader svg {
    @apply transform-[scale(0.6)] lg:transform-[scale(0.7)];
}

.sticker-loader #logo-icon {
    transform-box: fill-box;
    transform-origin: 50% 50%;
    will-change: transform;
    animation: sticker-logo-bounce 0.6s infinite;
}

@media (prefers-reduced-motion: reduce) {
    .sticker-loader #logo-icon {
        animation: none;
        will-change: auto;
        transform: none;
    }
}

/* ──────────────────────────────────────────────────────────────── */

#smooth-wrapper {
    overflow: clip;
}

#smooth-content {
    will-change: transform;
}

.global-page-loader {
    position: fixed;
    inset: 0;
    z-index: 1000;
    display: grid;
    place-items: center;
    background: var(--background);
    opacity: 1;
    visibility: visible;
    transition: opacity 280ms ease, visibility 280ms ease;
}

svg {
    /*width: 100%;*/
    /*height: 100%;*/
    overflow: visible;
}

.rec-one {
    visibility: hidden;
    filter: drop-shadow(0px 17px 5px var(--muted));
}

.leave-svg {
    @apply -translate-x-2.5 sm:translate-x-[-150px] lg:-translate-x-2.5;
}

.stepper-track {
    --stepper-indicator-top: 0px;
    --stepper-indicator-height: 0px;
    position: relative;
}

.stepper-track::before {
    position: absolute;
    display: block;
    content: '';
    top: 0;
    left: 0;
    width: 8px;
    height: 100%;
    border-radius: 20px;
    background: var(--primary-50);
}

.stepper-track::after {
    position: absolute;
    display: block;
    content: '';
    top: 0;
    left: 0;
    width: 8px;
    height: var(--stepper-indicator-height);
    border-radius: 16px;
    background: var(--primary);
    transform: translateY(var(--stepper-indicator-top));
    transition: transform 300ms ease-out, height 300ms ease-out;
}

@media (prefers-reduced-motion: reduce) {
    #smooth-content {
        transform: none !important;
        will-change: auto;
    }

    .stepper-track::after {
        transition: none;
    }
}

[data-header-text] {
    position: relative;
    overflow: hidden;
}

/*[data-header-text] h1 {*/
/*    @apply translate-y-20;*/
/*}*/

